import{_ as t,o,c as a,ag as r}from"./chunks/framework.Nx1zvZTu.js";const p=JSON.parse('{"title":"HTTP endpoints (v5.0.0)","description":"","frontmatter":{},"headers":[],"relativePath":"reference/api/endpoints.md","filePath":"reference/api/endpoints.md"}'),d={name:"reference/api/endpoints.md"};function c(s,e,i,n,l,h){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="http-endpoints-v5-0-0" tabindex="-1">HTTP endpoints (v5.0.0) <a class="header-anchor" href="#http-endpoints-v5-0-0" aria-label="Permalink to &quot;HTTP endpoints (v5.0.0)&quot;">​</a></h1><p>Domain-agnostic remote-call, storage, and search API for machinable.</p><p>A <strong>generic substrate</strong> for driving <code>machinable.Interface</code> subclasses remotely: transport (JSON control plane + binary data plane), a config/identity <strong>index</strong> with <strong>search</strong>, and an Execution lifecycle. Each <em>interface</em> (a Python module in the project) decides what bytes and method calls mean while machinable stays use-case-agnostic.</p><h3 id="conceptual-model" tabindex="-1">Conceptual model <a class="header-anchor" href="#conceptual-model" aria-label="Permalink to &quot;Conceptual model&quot;">​</a></h3><ul><li><strong>Interface</strong>: a materialized data node (config + identity). <code>InterfaceInfo</code> carries no lifecycle status.</li><li><strong>Execution</strong>: the only run-record with lifecycle (<code>is_active</code>, timestamps).</li><li><strong>Project</strong>: the unit a request binds to. Multiple projects (and Python interpreters) are served from one gateway.</li></ul><h3 id="discovering-the-full-contract" tabindex="-1">Discovering the full contract <a class="header-anchor" href="#discovering-the-full-contract" aria-label="Permalink to &quot;Discovering the full contract&quot;">​</a></h3><ul><li><strong>REST</strong>: this OpenAPI document (<code>/openapi.json</code>, <code>/docs</code>).</li><li><strong>WebSocket protocol</strong> (connect / call / stream / chunk upload / chunk read / event): <code>GET /v1/protocol</code> returns a machine-readable description, since OpenAPI cannot model WebSocket frames.</li></ul><h3 id="request-routing-headers-query-equivalents-in-parentheses" tabindex="-1">Request routing (headers; query equivalents in parentheses) <a class="header-anchor" href="#request-routing-headers-query-equivalents-in-parentheses" aria-label="Permalink to &quot;Request routing (headers; query equivalents in parentheses)&quot;">​</a></h3><ul><li><code>X-Machinable-Project</code> (<code>?project=</code>): target project, must be under the server&#39;s allowlist; defaults to the launch project.</li><li><code>X-Machinable-User</code> (<code>X-Machinable-User</code>): attributes created interfaces (<code>created_by</code>); defaults to the server OS user.</li><li><code>X-Machinable-Python</code> (<code>?python=</code>): interpreter; a non-gateway interpreter is routed to a subprocess worker.</li><li><code>Authorization: Bearer &lt;token&gt;</code>: required when the server sets <code>api_token</code> (<code>/docs</code> and <code>/openapi.json</code> are exempt).</li></ul><h3 id="capability-map" tabindex="-1">Capability map <a class="header-anchor" href="#capability-map" aria-label="Permalink to &quot;Capability map&quot;">​</a></h3><p><code>remote_call</code>, <code>binary_upload</code>, <code>binary_read</code>, <code>config_search</code>, <code>create_by_id</code>, <code>mutable_label</code>, <code>creator_attribution</code>, <code>multi_project</code>; see <code>/v1/protocol</code> for the surfaces that expose each.</p><h2 id="rest-endpoints" tabindex="-1">REST endpoints <a class="header-anchor" href="#rest-endpoints" aria-label="Permalink to &quot;REST endpoints&quot;">​</a></h2><h3 id="interfaces" tabindex="-1">interfaces <a class="header-anchor" href="#interfaces" aria-label="Permalink to &quot;interfaces&quot;">​</a></h3><p>Create/attach interfaces, invoke methods, search by config, set the mutable label, read files, and the WebSocket data plane.</p><h4 id="get-v1-interfaces" tabindex="-1"><code>GET /v1/interfaces</code> <a class="header-anchor" href="#get-v1-interfaces" aria-label="Permalink to &quot;`GET /v1/interfaces`&quot;">​</a></h4><p><em>List Interfaces</em></p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#interfaceinfo"><code>InterfaceInfo[]</code></a></li></ul><h4 id="post-v1-interfaces" tabindex="-1"><code>POST /v1/interfaces</code> <a class="header-anchor" href="#post-v1-interfaces" aria-label="Permalink to &quot;`POST /v1/interfaces`&quot;">​</a></h4><p><em>Create Interface</em></p><p>Create (materialize) an interface, optionally with a client-supplied id.</p><p>Idempotent in <code>uuid</code>: creating again with the same id returns the existing instance unchanged (content-addressed dedupe).</p><p><strong>Request body:</strong> <a href="./schemas.html#createinterfacerequest"><code>CreateInterfaceRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#interfaceinfo"><code>InterfaceInfo</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-interfaces-search" tabindex="-1"><code>POST /v1/interfaces/search</code> <a class="header-anchor" href="#post-v1-interfaces-search" aria-label="Permalink to &quot;`POST /v1/interfaces/search`&quot;">​</a></h4><p><em>Search</em></p><p>Generic config search over interface instances (operators, sort, paging).</p><p><strong>Request body:</strong> <a href="./schemas.html#findrequest"><code>FindRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#searchresponse"><code>SearchResponse</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-interfaces-resolve" tabindex="-1"><code>POST /v1/interfaces/resolve</code> <a class="header-anchor" href="#post-v1-interfaces-resolve" aria-label="Permalink to &quot;`POST /v1/interfaces/resolve`&quot;">​</a></h4><p><em>Resolve</em></p><p>Dry-run a compact version → resolved config + CLI, without materializing.</p><p><strong>Request body:</strong> <a href="./schemas.html#resolverequest"><code>ResolveRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#resolveresponse"><code>ResolveResponse</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-interfaces-lifecycle" tabindex="-1"><code>POST /v1/interfaces/lifecycle</code> <a class="header-anchor" href="#post-v1-interfaces-lifecycle" aria-label="Permalink to &quot;`POST /v1/interfaces/lifecycle`&quot;">​</a></h4><p><em>Lifecycle</em></p><p>Content-addressed compute lifecycle for a config.</p><p>One of: draft / running / cached / failed.</p><p><strong>Request body:</strong> <a href="./schemas.html#lifecyclerequest"><code>LifecycleRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#lifecycleresponse"><code>LifecycleResponse</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-interfaces-call" tabindex="-1"><code>POST /v1/interfaces/call</code> <a class="header-anchor" href="#post-v1-interfaces-call" aria-label="Permalink to &quot;`POST /v1/interfaces/call`&quot;">​</a></h4><p><em>Call Interface</em></p><p><strong>Request body:</strong> <a href="./schemas.html#interfacecallrequest"><code>InterfaceCallRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#object"><code>object</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-interfaces-uuid" tabindex="-1"><code>GET /v1/interfaces/{uuid}</code> <a class="header-anchor" href="#get-v1-interfaces-uuid" aria-label="Permalink to &quot;`GET /v1/interfaces/{uuid}`&quot;">​</a></h4><p><em>Get Interface</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#interfaceinfo"><code>InterfaceInfo</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="delete-v1-interfaces-uuid" tabindex="-1"><code>DELETE /v1/interfaces/{uuid}</code> <a class="header-anchor" href="#delete-v1-interfaces-uuid" aria-label="Permalink to &quot;`DELETE /v1/interfaces/{uuid}`&quot;">​</a></h4><p><em>Delete Interface</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>204</code> Successful Response</li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="patch-v1-interfaces-uuid-label" tabindex="-1"><code>PATCH /v1/interfaces/{uuid}/label</code> <a class="header-anchor" href="#patch-v1-interfaces-uuid-label" aria-label="Permalink to &quot;`PATCH /v1/interfaces/{uuid}/label`&quot;">​</a></h4><p><em>Set Interface Label</em></p><p>Set/replace an interface&#39;s mutable label (FCFS / last-write-wins).</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Request body:</strong> <a href="./schemas.html#setlabelrequest"><code>SetLabelRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#interfaceinfo"><code>InterfaceInfo</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-interfaces-uuid-executions" tabindex="-1"><code>GET /v1/interfaces/{uuid}/executions</code> <a class="header-anchor" href="#get-v1-interfaces-uuid-executions" aria-label="Permalink to &quot;`GET /v1/interfaces/{uuid}/executions`&quot;">​</a></h4><p><em>List Interface Executions</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr><tr><td><code>active</code></td><td>query</td><td>no</td><td></td></tr><tr><td><code>limit</code> (integer)</td><td>query</td><td>no</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#executioninfo"><code>ExecutionInfo[]</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-interfaces-uuid-provenance" tabindex="-1"><code>GET /v1/interfaces/{uuid}/provenance</code> <a class="header-anchor" href="#get-v1-interfaces-uuid-provenance" aria-label="Permalink to &quot;`GET /v1/interfaces/{uuid}/provenance`&quot;">​</a></h4><p><em>Get Provenance</em></p><p>The provenance graph: how this interface came to be.</p><p>Recipe (config/context/derivation) plus history (executions, each with the Manifest it used), as a normalized node-link DAG. <code>depth</code> bounds the walk; <code>rels</code> (comma-separated edge labels, e.g. <code>derivation,runs,manifest</code>) overrides the default policy.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr><tr><td><code>depth</code> (integer)</td><td>query</td><td>no</td><td></td></tr><tr><td><code>rels</code></td><td>query</td><td>no</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#provenancegraph"><code>ProvenanceGraph</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-interfaces-uuid-data" tabindex="-1"><code>GET /v1/interfaces/{uuid}/data</code> <a class="header-anchor" href="#get-v1-interfaces-uuid-data" aria-label="Permalink to &quot;`GET /v1/interfaces/{uuid}/data`&quot;">​</a></h4><p><em>Get Data Status</em></p><p>Whether the run&#39;s stored data is readable now (local / remote / evicted).</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#datastatusresponse"><code>DataStatusResponse</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-interfaces-uuid-related" tabindex="-1"><code>GET /v1/interfaces/{uuid}/related</code> <a class="header-anchor" href="#get-v1-interfaces-uuid-related" aria-label="Permalink to &quot;`GET /v1/interfaces/{uuid}/related`&quot;">​</a></h4><p><em>Get Related</em></p><p>The interface&#39;s lineage neighbours (derived, uses, executions, …).</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#relatedresponse"><code>RelatedResponse</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-interfaces-uuid-archive" tabindex="-1"><code>POST /v1/interfaces/{uuid}/archive</code> <a class="header-anchor" href="#post-v1-interfaces-uuid-archive" aria-label="Permalink to &quot;`POST /v1/interfaces/{uuid}/archive`&quot;">​</a></h4><p><em>Archive Interface</em></p><p>Soft-archive (hide) an interface, or restore it with ?restore=true.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr><tr><td><code>restore</code> (boolean)</td><td>query</td><td>no</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#interfaceinfo"><code>InterfaceInfo</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-interfaces-uuid-files" tabindex="-1"><code>GET /v1/interfaces/{uuid}/files</code> <a class="header-anchor" href="#get-v1-interfaces-uuid-files" aria-label="Permalink to &quot;`GET /v1/interfaces/{uuid}/files`&quot;">​</a></h4><p><em>List Files</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#object"><code>object</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-interfaces-uuid-files-path" tabindex="-1"><code>GET /v1/interfaces/{uuid}/files/{path}</code> <a class="header-anchor" href="#get-v1-interfaces-uuid-files-path" aria-label="Permalink to &quot;`GET /v1/interfaces/{uuid}/files/{path}`&quot;">​</a></h4><p><em>Read File</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr><tr><td><code>path</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response</li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h3 id="executions" tabindex="-1">executions <a class="header-anchor" href="#executions" aria-label="Permalink to &quot;executions&quot;">​</a></h3><p>Dispatch runs and query Execution lifecycle status and output.</p><h4 id="get-v1-executions" tabindex="-1"><code>GET /v1/executions</code> <a class="header-anchor" href="#get-v1-executions" aria-label="Permalink to &quot;`GET /v1/executions`&quot;">​</a></h4><p><em>List All Executions</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>active</code></td><td>query</td><td>no</td><td></td></tr><tr><td><code>incomplete</code></td><td>query</td><td>no</td><td></td></tr><tr><td><code>parent</code></td><td>query</td><td>no</td><td></td></tr><tr><td><code>limit</code> (integer)</td><td>query</td><td>no</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#executioninfo"><code>ExecutionInfo[]</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-executions" tabindex="-1"><code>POST /v1/executions</code> <a class="header-anchor" href="#post-v1-executions" aria-label="Permalink to &quot;`POST /v1/executions`&quot;">​</a></h4><p><em>Dispatch Execution</em></p><p>Dispatch interfaces into an Execution, each under its context stack.</p><p>Mirrors the CLI element chain (<code>machinable get … --launch</code>): for each interface, the context interfaces are entered in order (and exited in reverse) so their predicates fold into the interface&#39;s identity at materialization; the interfaces are added to the Execution container, which is then dispatched. Project is the request&#39;s ambient project.</p><p><strong>Request body:</strong> <a href="./schemas.html#dispatchrequest"><code>DispatchRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#executioninfo"><code>ExecutionInfo</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-executions-uuid" tabindex="-1"><code>GET /v1/executions/{uuid}</code> <a class="header-anchor" href="#get-v1-executions-uuid" aria-label="Permalink to &quot;`GET /v1/executions/{uuid}`&quot;">​</a></h4><p><em>Get Execution</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#executioninfo"><code>ExecutionInfo</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-executions-uuid-output" tabindex="-1"><code>GET /v1/executions/{uuid}/output</code> <a class="header-anchor" href="#get-v1-executions-uuid-output" aria-label="Permalink to &quot;`GET /v1/executions/{uuid}/output`&quot;">​</a></h4><p><em>Get Execution Output</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#object"><code>object</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-executions-uuid-cancel" tabindex="-1"><code>POST /v1/executions/{uuid}/cancel</code> <a class="header-anchor" href="#post-v1-executions-uuid-cancel" aria-label="Permalink to &quot;`POST /v1/executions/{uuid}/cancel`&quot;">​</a></h4><p><em>Cancel Execution</em></p><p>Best-effort cancel: write a <code>cancelled</code> marker into the run&#39;s directory.</p><p>A live dispatch&#39;s watcher polls for it and injects ExecutionInterrupted; a not-yet- started or already-finished run simply carries the marker (a no-op). No execution- engine coupling.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>uuid</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>204</code> Successful Response</li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h3 id="project" tabindex="-1">project <a class="header-anchor" href="#project" aria-label="Permalink to &quot;project&quot;">​</a></h3><p>Discover Interface modules and reflect their Config schemas.</p><h4 id="get-v1-project" tabindex="-1"><code>GET /v1/project</code> <a class="header-anchor" href="#get-v1-project" aria-label="Permalink to &quot;`GET /v1/project`&quot;">​</a></h4><p><em>List Project Modules</em></p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#projectindex"><code>ProjectIndex</code></a></li></ul><h4 id="get-v1-project-remotes" tabindex="-1"><code>GET /v1/project/remotes</code> <a class="header-anchor" href="#get-v1-project-remotes" aria-label="Permalink to &quot;`GET /v1/project/remotes`&quot;">​</a></h4><p><em>Get Remotes</em></p><p>Shareable interfaces the project resolves by URL (slurm, globus, …).</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#remotesresponse"><code>RemotesResponse</code></a></li></ul><h4 id="get-v1-project-module-widget-asset" tabindex="-1"><code>GET /v1/project/{module}/widget/{asset}</code> <a class="header-anchor" href="#get-v1-project-module-widget-asset" aria-label="Permalink to &quot;`GET /v1/project/{module}/widget/{asset}`&quot;">​</a></h4><p><em>Get Widget Asset</em></p><p>Serve a widget&#39;s ES module or stylesheet (module-level assets).</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>module</code> (string)</td><td>path</td><td>yes</td><td></td></tr><tr><td><code>asset</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response</li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-project-module" tabindex="-1"><code>GET /v1/project/{module}</code> <a class="header-anchor" href="#get-v1-project-module" aria-label="Permalink to &quot;`GET /v1/project/{module}`&quot;">​</a></h4><p><em>Get Module Schema</em></p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>module</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#moduleschema"><code>ModuleSchema</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="get-v1-projects" tabindex="-1"><code>GET /v1/projects</code> <a class="header-anchor" href="#get-v1-projects" aria-label="Permalink to &quot;`GET /v1/projects`&quot;">​</a></h4><p><em>List Open Projects</em></p><p>List the projects the server can serve.</p><p>The default, any with live state, the allowlist roots, and any process-isolated workers currently running.</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#object"><code>object</code></a></li></ul><h3 id="source" tabindex="-1">source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;source&quot;">​</a></h3><p>Read/write/create/rename/delete interface source files (opt-in, token-gated; confined to the project base directory).</p><h4 id="get-v1-source" tabindex="-1"><code>GET /v1/source</code> <a class="header-anchor" href="#get-v1-source" aria-label="Permalink to &quot;`GET /v1/source`&quot;">​</a></h4><p><em>List Source</em></p><p>List the editable source files under the project base directory.</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#sourcelistresponse"><code>SourceListResponse</code></a></li></ul><h4 id="get-v1-source-path" tabindex="-1"><code>GET /v1/source/{path}</code> <a class="header-anchor" href="#get-v1-source-path" aria-label="Permalink to &quot;`GET /v1/source/{path}`&quot;">​</a></h4><p><em>Read Source</em></p><p>Read a file&#39;s content; the strong ETag (MD5) is also a response header.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>path</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#sourcefilecontent"><code>SourceFileContent</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="put-v1-source-path" tabindex="-1"><code>PUT /v1/source/{path}</code> <a class="header-anchor" href="#put-v1-source-path" aria-label="Permalink to &quot;`PUT /v1/source/{path}`&quot;">​</a></h4><p><em>Write Source</em></p><p>Create or fully overwrite a file.</p><p>Conditional writes: <code>If-Match: &quot;&amp;lt;etag&gt;&quot;</code> (or <code>*</code>) returns 412 on a stale ETag; <code>If-None-Match: *</code> returns 412 if the file already exists (create-only). Editing invalidates caches made stale by the change.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>path</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Request body:</strong> <a href="./schemas.html#sourcewriterequest"><code>SourceWriteRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#sourcewriteresponse"><code>SourceWriteResponse</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="delete-v1-source-path" tabindex="-1"><code>DELETE /v1/source/{path}</code> <a class="header-anchor" href="#delete-v1-source-path" aria-label="Permalink to &quot;`DELETE /v1/source/{path}`&quot;">​</a></h4><p><em>Delete Source</em></p><p>Delete a source file and invalidate caches made stale by its removal.</p><table tabindex="0"><thead><tr><th>Parameter</th><th>In</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><code>path</code> (string)</td><td>path</td><td>yes</td><td></td></tr></tbody></table><p><strong>Responses:</strong></p><ul><li><code>204</code> Successful Response</li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h4 id="post-v1-source-move" tabindex="-1"><code>POST /v1/source/move</code> <a class="header-anchor" href="#post-v1-source-move" aria-label="Permalink to &quot;`POST /v1/source/move`&quot;">​</a></h4><p><em>Move Source</em></p><p>Atomically rename/move a file within the base directory.</p><p>Handles interface renames, including converting a single-file module to a package layout (<code>foo.py</code> → <code>foo/__init__.py</code>) and back.</p><p><strong>Request body:</strong> <a href="./schemas.html#sourcemoverequest"><code>SourceMoveRequest</code></a> (required)</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#sourcewriteresponse"><code>SourceWriteResponse</code></a></li><li><code>422</code> Validation Error → <a href="./schemas.html#httpvalidationerror"><code>HTTPValidationError</code></a></li></ul><h3 id="meta" tabindex="-1">meta <a class="header-anchor" href="#meta" aria-label="Permalink to &quot;meta&quot;">​</a></h3><p>Self-description: the WebSocket protocol, interface hooks, and capability map that OpenAPI cannot express.</p><h4 id="get-v1-protocol" tabindex="-1"><code>GET /v1/protocol</code> <a class="header-anchor" href="#get-v1-protocol" aria-label="Permalink to &quot;`GET /v1/protocol`&quot;">​</a></h4><p><em>Describe the WebSocket protocol and capability map</em></p><p>Return the non-OpenAPI half of the contract.</p><p>Includes every WebSocket frame type, the binary upload/read sequences, the interface hooks a project implements (<code>read</code>, <code>emit</code>, callable methods), cross-cutting request headers, and the capability map.</p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#protocoldoc"><code>ProtocolDoc</code></a></li></ul><h3 id="health" tabindex="-1">health <a class="header-anchor" href="#health" aria-label="Permalink to &quot;health&quot;">​</a></h3><p>Server status, version, and active execution count.</p><h4 id="get-v1-health" tabindex="-1"><code>GET /v1/health</code> <a class="header-anchor" href="#get-v1-health" aria-label="Permalink to &quot;`GET /v1/health`&quot;">​</a></h4><p><em>Health</em></p><p><strong>Responses:</strong></p><ul><li><code>200</code> Successful Response → <a href="./schemas.html#healthresponse"><code>HealthResponse</code></a></li></ul>',213)])])}const m=t(d,[["render",c]]);export{p as __pageData,m as default};
